// fetch-based HTTP helpers (replaces axios to avoid task runner crash)
async function _post(url, data, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'POST', headers: headers, body: JSON.stringify(data), signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _get(url, opts) {
  var qurl = url;
  if (opts && opts.params) { var qs = new URLSearchParams(opts.params).toString(); if (qs) qurl += (url.includes('?') ? '&' : '?') + qs; }
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(qurl, {headers: headers, signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _del(url, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'DELETE', headers: headers, body: opts && opts.data ? JSON.stringify(opts.data) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _put(url, body, opts) {
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'PUT', headers: headers, body: typeof body === 'string' ? body : JSON.stringify(body)});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  return {data: json, status: r.status};
}
const body = $('Agents Webhook').first().json.body || {};
const MLFLOW = ($env.MLFLOW_TRACKING_URI || 'http://mlflow:5050') + '/api/2.0/mlflow';

var action = body.action || 'list';
var agentName = body.name || '';

function parseTags(tagArr) {
  var m = {};
  if (!tagArr) return m;
  for (var i = 0; i < tagArr.length; i++) m[tagArr[i].key] = tagArr[i].value;
  return m;
}

async function getAgentInfo(model) {
  var name = model.name.replace('.SYSTEM', '');
  var modelTags = parseTags(model.tags);
  var cfg = {};
  try { cfg = JSON.parse(modelTags['agent.config'] || '{}'); } catch(e) {}

  // Determine mode
  var mode = cfg.mcp_tools ? 'agent' : 'chat';

  // Get latest version info
  var latestVersions = model.latest_versions || [];
  var latestVersion = latestVersions.length > 0 ? latestVersions[latestVersions.length - 1] : null;
  var versionNumber = latestVersion ? latestVersion.version : '0';

  // Resolve production alias
  var aliases = model.aliases || [];
  var prodAlias = null;
  for (var i = 0; i < aliases.length; i++) {
    if (aliases[i].alias === 'production') { prodAlias = aliases[i].version; break; }
  }

  // Enumerate tasks
  var tasks = [];
  try {
    var taskResp = await _get(MLFLOW + '/registered-models/search', {
      params: {
        filter: "name LIKE '" + name + ".%' AND tags.`mlflow.prompt.is_prompt` = 'true'",
        max_results: 100
      },
      timeout: 10000
    });
    var taskModels = taskResp.data.registered_models || [];
    for (var j = 0; j < taskModels.length; j++) {
      var tName = taskModels[j].name;
      if (tName !== model.name) {
        var taskKey = tName.substring(name.length + 1);
        var taskTags = parseTags(taskModels[j].tags);
        tasks.push({
          name: taskKey,
          description: taskTags['task.description'] || ''
        });
      }
    }
  } catch (e) { /* non-fatal */ }

  // Promotion status
  var promotion = {
    production_version: prodAlias ? parseInt(prodAlias) : parseInt(versionNumber),
    staging_version: null,
    canary_enabled: false,
    canary_pct: 0,
    last_benchmark: null,
    last_promotion: null
  };
  // Read canary tags
  if (modelTags['canary.enabled'] === 'true') {
    promotion.canary_enabled = true;
    promotion.staging_version = modelTags['canary.staging_version'] ? parseInt(modelTags['canary.staging_version']) : null;
    promotion.canary_pct = parseInt(modelTags['canary.traffic_pct'] || '0');
  }
  // Check for staging alias
  for (var ai = 0; ai < aliases.length; ai++) {
    if (aliases[ai].alias === 'staging') {
      promotion.staging_version = parseInt(aliases[ai].version);
      break;
    }
  }
  // Get latest promotion from {name}-promotions experiment
  try {
    var promExpRes = await _get(MLFLOW + '/experiments/get-by-name', {
      params: {experiment_name: name + '-promotions'},
      timeout: 5000
    });
    var promExpId = promExpRes.data.experiment.experiment_id;
    var promSearch = await _post(MLFLOW + '/runs/search', {
      experiment_ids: [promExpId],
      max_results: 1,
      order_by: ['start_time DESC']
    }, {timeout: 5000});
    var promRuns = promSearch.data.runs || [];
    if (promRuns.length > 0) {
      var pr = promRuns[0];
      var prParams = {};
      (pr.data && pr.data.params || []).forEach(function(p) { prParams[p.key] = p.value; });
      var prMetrics = {};
      (pr.data && pr.data.metrics || []).forEach(function(m) { prMetrics[m.key] = m.value; });
      promotion.last_promotion = {
        decision: prParams.decision || '',
        staging_version: prParams.staging_version || '',
        score: prMetrics.staging_score || 0,
        timestamp: new Date(Number(pr.info.start_time)).toISOString()
      };
      promotion.last_benchmark = {
        score: prMetrics.staging_score || 0,
        pass_rate: prMetrics.pass_rate || 0,
        run_id: pr.info.run_id,
        timestamp: new Date(Number(pr.info.start_time)).toISOString()
      };
    }
  } catch(promErr) { /* no promotions yet */ }

  return {
    name: name,
    description: cfg.description || '',
    mode: mode,
    mcp_tools: cfg.mcp_tools ? (cfg.mcp_tools === 'all' ? ['all'] : cfg.mcp_tools.split(',').map(function(t){ return t.trim(); })) : [],
    skills: cfg.skills || [],
    tasks: tasks,
    tags: cfg.tags || [],
    prompt_version: parseInt(prodAlias || versionNumber),
    prompt_alias: prodAlias ? 'production' : 'latest',
    promotion: promotion,
    config: {
      provider: cfg.provider || 'ollama',
      model: cfg.model || '',
      temperature: cfg.temperature || 0.3,
      top_p: cfg.top_p || 0.9,
      num_ctx: cfg.num_ctx || 32768,
      max_iterations: cfg.max_iterations || 10
    }
  };
}

try {
  if (action === 'list') {
    // Search for all *.SYSTEM models
    var resp = await _get(MLFLOW + '/registered-models/search', {
      params: {
        filter: "name LIKE '%.SYSTEM' AND tags.`mlflow.prompt.is_prompt` = 'true'",
        max_results: 100
      },
      timeout: 15000
    });
    var models = resp.data.registered_models || [];
    var agents = [];
    for (var i = 0; i < models.length; i++) {
      agents.push(await getAgentInfo(models[i]));
    }
    agents.sort(function(a, b) { return a.name.localeCompare(b.name); });
    return [{ json: { _error: false, agents: agents, count: agents.length } }];

  } else if (action === 'get') {
    if (!agentName) {
      return [{ json: { _error: true, error: 'Missing required field: name' } }];
    }
    var modelName = agentName + '.SYSTEM';
    var resp = await _get(MLFLOW + '/registered-models/get', {
      params: { name: modelName },
      timeout: 10000
    });
    var model = resp.data.registered_model;
    if (!model) {
      return [{ json: { _error: true, error: 'Agent not found: ' + agentName } }];
    }
    var agent = await getAgentInfo(model);

    // Also fetch the full prompt template for get action
    try {
      var versionToFetch = agent.prompt_version;
      var vResp = await _get(MLFLOW + '/model-versions/get', {
        params: { name: modelName, version: String(versionToFetch) },
        timeout: 10000
      });
      var version = vResp.data.model_version;
      var vTags = parseTags(version.tags);
      agent.template = vTags['mlflow.prompt.text'] || '';
    } catch (e) { agent.template = ''; }

    return [{ json: { _error: false, agent: agent } }];

  } else if (action === 'create') {
    if (!agentName) return [{ json: { _error: true, error: 'Missing required field: name' } }];

    var template = body.system_prompt || body.template || 'You are a helpful AI assistant.';
    var cfg = body.config || {};
    var description = body.description || cfg.description || '';

    var agentConfig = {
      provider: cfg.provider || 'ollama',
      model: cfg.model || '',
      temperature: cfg.temperature || 0.3,
      top_p: cfg.top_p || 0.9,
      num_ctx: cfg.num_ctx || 32768,
      max_iterations: cfg.max_iterations || 10,
      mcp_tools: cfg.mcp_tools || '',
      skills: cfg.skills || [],
      description: description,
      tags: cfg.tags || []
    };

    var modelName = agentName + '.SYSTEM';

    try {
      await _post(MLFLOW + '/registered-models/create', {
        name: modelName,
        tags: [
          { key: 'mlflow.prompt.is_prompt', value: 'true' },
          { key: 'use_case', value: 'agent' },
          { key: 'agent.config', value: JSON.stringify(agentConfig) }
        ]
      }, { timeout: 10000 });
    } catch(createErr) {
      if (createErr.response && createErr.response.data && String(createErr.response.data.error_code).indexOf('ALREADY_EXISTS') >= 0) {
        return [{ json: { _error: true, error: 'Agent already exists: ' + agentName } }];
      }
      throw createErr;
    }

    var mvResp = await _post(MLFLOW + '/model-versions/create', {
      name: modelName,
      source: 'prompt://agents/' + agentName,
      tags: [{ key: 'mlflow.prompt.text', value: template }]
    }, { timeout: 10000 });
    var newVer = mvResp.data.model_version.version;

    await _post(MLFLOW + '/registered-models/alias', {
      name: modelName, alias: 'production', version: String(newVer)
    }, { timeout: 10000 });

    return [{ json: { _error: false, status: 'created', name: agentName, version: parseInt(newVer) } }];

  } else if (action === 'update') {
    if (!agentName) return [{ json: { _error: true, error: 'Missing required field: name' } }];

    var modelName = agentName + '.SYSTEM';
    var existing;
    try {
      existing = await _get(MLFLOW + '/registered-models/get', {
        params: { name: modelName }, timeout: 10000
      });
    } catch(getErr) {
      return [{ json: { _error: true, error: 'Agent not found: ' + agentName } }];
    }

    if (body.config || body.description) {
      var existingTags = parseTags(existing.data.registered_model.tags);
      var existingCfg = {};
      try { existingCfg = JSON.parse(existingTags['agent.config'] || '{}'); } catch(pe) {}
      var newCfg = Object.assign({}, existingCfg, body.config || {});
      if (body.description) newCfg.description = body.description;

      await _post(MLFLOW + '/registered-models/set-tag', {
        name: modelName, key: 'agent.config', value: JSON.stringify(newCfg)
      }, { timeout: 10000 });
    }

    var version = null;
    if (body.system_prompt || body.template) {
      var tmpl = body.system_prompt || body.template;
      var mvResp = await _post(MLFLOW + '/model-versions/create', {
        name: modelName,
        source: 'prompt://agents/' + agentName,
        tags: [{ key: 'mlflow.prompt.text', value: tmpl }]
      }, { timeout: 10000 });
      version = parseInt(mvResp.data.model_version.version);
    }

    return [{ json: { _error: false, status: 'updated', name: agentName, version: version } }];

  } else if (action === 'delete') {
    if (!agentName) return [{ json: { _error: true, error: 'Missing required field: name' } }];

    var seedAgents = ['mlops', 'coder', 'writer', 'reasoner', 'devops', 'analyst', 'mcp'];
    if (seedAgents.indexOf(agentName) >= 0) {
      return [{ json: { _error: true, error: 'Cannot delete seed agent: ' + agentName } }];
    }

    var modelName = agentName + '.SYSTEM';
    try {
      await _del(MLFLOW + '/registered-models/delete', {
        data: { name: modelName }, timeout: 10000
      });
    } catch(delErr) {
      return [{ json: { _error: true, error: 'Agent not found or cannot delete: ' + agentName } }];
    }

    return [{ json: { _error: false, status: 'deleted', name: agentName } }];

  } else {
    return [{ json: { _error: true, error: 'Unknown action: ' + action + '. Supported: list, get, create, update, delete' } }];
  }
} catch (e) {
  return [{ json: { _error: true, error: e.message || String(e) } }];
}
